{
  "evaluation_of_each_diagnosis": {
    "Hypervirulent Klebsiella pneumoniae (hvKP) syndrome": {
      "supporting_facts": "The classic triad of liver abscess, metastatic pulmonary nodules, and endophthalmitis (the 'KLA syndrome').",
      "against_facts": "No specific history of diabetes mellitus (though not strictly required).",
      "support_level": "Well-supported"
    },
    "Disseminated melioidosis": {
      "supporting_facts": "Pulmonary nodules/cavitation, liver abscesses, metastatic infection, and demographic origin from an endemic region.",
      "against_facts": "Lack of clear direct exposure history; patient moved from Caribbean as an infant.",
      "support_level": "Well-supported"
    },
    "Disseminated nocardiosis": {
      "supporting_facts": "Pulmonary cavitation and multiple brain/systemic abscesses.",
      "against_facts": "Endophthalmitis is less common than in hvKP; typically associated with immunocompromise.",
      "support_level": "Weakly supported"
    },
    "Infective endocarditis": {
      "supporting_facts": "Fever, leukocytosis, septic emboli to eyes and brain.",
      "against_facts": "Echocardiogram was negative for vegetation; ocular findings are more consistent with primary metastatic focus than embolic phenomenon from a valve.",
      "support_level": "Weakly supported"
    },
    "Disseminated fungal infection": {
      "supporting_facts": "Can cause endophthalmitis and abscesses.",
      "against_facts": "Lack of clear immunosuppressive history or prolonged antibiotic use pre-presentation; less likely to cause such a large, singular hepatic mass.",
      "support_level": "Weakly supported"
    },
    "Metastatic malignancy": {
      "supporting_facts": "Weight loss, pulmonary nodules, hepatic mass.",
      "against_facts": "Acute presentation with high fever, marked leukocytosis, and vitreous abscess is more consistent with infection than necrotic tumor.",
      "support_level": "Weakly supported"
    }
  },
